\begin{lemma} 
\label{lem:haar-smallball-simple}
Let $q$ be uniform on $\mathbb{S}^{d-1}$ and fix any $v\in\mathbb{S}^{d-1}$.
Then for every $\rho\in[0,1]$,
\[
\mathbb{P}\big(|\langle v,q\rangle|\le \rho\big)\ \le\ \sqrt{\frac{2d}{\pi}}\,\rho.
\]
\end{lemma}

